"use strict";(self.webpackChunkzebra_iotc_devportal=self.webpackChunkzebra_iotc_devportal||[]).push([[2190],{49059:n=>{n.exports=JSON.parse('{"id":"plugin-asyncapi-0","themeId":"theme-asyncapi","title":"Zebra Handheld RFID Reader IoT Connector - MQTT API","description":"Complete MQTT API reference for Zebra IoT Connector (IOTC) on **RFD40 / RFD90 Series** handheld RFID readers.\\n\\n## Overview\\n\\nThe API enables **cloud-based device management**, **RFID operation control**, **tag data collection**, and **fleet monitoring** via MQTT 3.1.1 messaging.\\n\\n### Interfaces\\n\\n| Interface | Purpose | Channels |\\n|-----------|---------|----------|\\n| **MGMT** | Device management, monitoring, firmware | cmnd, resp, event |\\n| **CTRL** | RFID operation control and configuration | cmnd, resp |\\n| **DATA** | Tag data streaming | data1event, data2event |\\n\\n### Topic Pattern\\n\\n```\\n{tenantId}/{INTERFACE}/clients/{channel}/{deviceSerial}\\n```\\n\\n### Response Codes\\n\\n| Code | Meaning |\\n|------|---------|\\n| 0 | Success |\\n| 1 | Accepted (async processing) |\\n| 2 | Invalid payload |\\n| 3 | Unable to retrieve |\\n| 6 | Region not configured |\\n| 10 | Config already exists |\\n| 11 | Config not found / Inventory in progress |\\n| 12 | No operation in progress |\\n| 15 | SSID not found |\\n| 17 | SSID missing |\\n| 18 | Certificate parse error |\\n| 19 | Download failed |\\n| 20 | Firmware validation failed |\\n| 21 | Insufficient battery |\\n| 22 | Operation in progress |\\n| 23 | Invalid enum / Radio not connected |\\n| 24 | Max 32 pre-filters |\\n| 28 | Pattern too long / Not supported |\\n"}')}}]);